object AwsCredentialManager {

  def provider(
      accessKeyId: Option[String] = sys.env.get("AWS_ACCESS_KEY_ID"),
      secretAccessKey: Option[String] = sys.env.get("AWS_SECRET_ACCESS_KEY"),
      sessionToken: Option[String] = sys.env.get("AWS_SESSION_TOKEN")
  ): AwsCredentialsProvider = {

    (accessKeyId, secretAccessKey) match {
      case (Some(id), Some(secret)) =>
        val creds =
          sessionToken match {
            case Some(token) => AwsSessionCredentials.create(id, secret, token)
            case None        => AwsBasicCredentials.create(id, secret)
          }
        StaticCredentialsProvider.create(creds)
      case _ =>
        DefaultCredentialsProvider.create()
    }
  }
}

